import { run as loopClipRun } from './loopClip/library.js';
import { run as narratedStillRun } from './narratedStill/library.js';
import { run as pictureInPictureRun } from './pictureInPicture/library.js';
import { run as submitInventoryToTaskQueueRun } from './submitInventoryToTaskQueue/library.js';

const categoryMeta = await fetch(new URL('./category.json', import.meta.url)).then(r => r.json());
const loopClipMeta = await fetch(new URL('./loopClip/action.json', import.meta.url)).then(r => r.json());
const narratedStillMeta = await fetch(new URL('./narratedStill/action.json', import.meta.url)).then(r => r.json());
const pictureInPictureMeta = await fetch(new URL('./pictureInPicture/action.json', import.meta.url)).then(r => r.json());
const submitInventoryToTaskQueueMeta = await fetch(new URL('./submitInventoryToTaskQueue/action.json', import.meta.url)).then(r => r.json());

export const submitCategory = {
  name: `library/${categoryMeta.id}`,
  install(app) {
    app.registerCategory(categoryMeta, {
      [loopClipMeta.id]: { ...loopClipMeta, run: loopClipRun },
      [narratedStillMeta.id]: { ...narratedStillMeta, run: narratedStillRun },
      [pictureInPictureMeta.id]: { ...pictureInPictureMeta, run: pictureInPictureRun },
      [submitInventoryToTaskQueueMeta.id]: { ...submitInventoryToTaskQueueMeta, run: submitInventoryToTaskQueueRun },
    });
  },
};
